-6px 0 0 0;\n    position: absolute;\n    z-index: 820;\n    top: 100%;\n\n    &:before {\n        content: \"\";\n        display: inline-block;\n        position: absolute;\n        left: auto;\n        right: 14px;\n        top: -16px;\n        border: 8px solid transparent;\n        border-bottom-color: rgba(27, 31, 35, 0.15);\n    }\n\n    &:after {\n        content: \"\";\n        display: inline-block;\n        position: absolute;\n        left: auto;\n        right: 15px;\n        top: -14px;\n        border: 7px solid transparent;\n        border-bottom-color: #fff;\n    }\n}\n/*\n * Base.less\n * Author: iRuxu\n * Description: a simple and easy-to-use CSS framework, providing common writing combinations\n * Manual: http://csslab.cc\n */\n\n\n/* Font -------------------------------------*/\n\n    // Font size & line height\n    .fz(@font-size, @line-height: false) {\n        font-size: @font-size;\n        & when not (@line-height = false) {\n            line-height: @line-height;\n        }\n    }\n\n    // line height\n    .lh(@line-height, @height: false) {\n        line-height: @line-height;\n        & when not (@height = false) {\n            height: @height;\n        }\n    }\n\n    // Font style\n    .bold(@bold:bold){font-weight:@bold;}\n\n    .italic(){font-style:italic;}\n\n    .normal(){font-weight:normal;font-style:normal;}\n\n    .smooth(){\n        -webkit-font-smoothing:antialiased;\n        -moz-osx-font-smoothing:grayscale;\n    }\n\n    // Number\n    .number(@font-family: false) {\n        & when (@font-family = true) {\n            font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, \"Liberation Mono\", monospace;\n        }\n\n        & when (isstring(@font-family)) {\n            font-family: e(@font-family);\n        }\n\n        font-variant-numeric: tabular-nums slashed-zero;\n        font-feature-settings: \"tnum\" 1, \"zero\" 1;\n    }\n\n    // Font-Face\n    // 注意传参时，name后接分号\n    .fontface(@name; @sources...) {\n        @font-face {\n            font-family: @name;\n            src: @sources;\n            font-display: swap;\n        }\n    }\n\n    // Font color\n    .color(@color, @hovercolor: null) {\n        // 检查是否为纯色\n        & when (iscolor(@color)) {\n            color: @color;\n\n            & when (iscolor(@hovercolor)) {\n                &:hover {\n                    color: @hovercolor;\n                }\n            }\n        }\n        // 非纯色处理（背景填充逻辑）\n        & when not (iscolor(@color)) {\n            -webkit-background-clip: text;\n            -webkit-text-fill-color: transparent;\n            background-image: @color;\n        }\n    }\n\n    // Underline\n    .underline() {\n        .underline(3px, solid, currentColor);\n    }\n\n    .underline(@color) when (iscolor(@color)) {\n        .underline(3px, solid, @color);\n    }\n\n    .underline(@offset, @style, @color) {\n        text-decoration: underline;\n        text-decoration-color: @color;\n        text-decoration-style: @style;\n        text-underline-offset: @offset;\n    }\n\n\n/* Word -------------------------------------*/\n\n    // 不折行\n    .nobreak(@style:ellipsis){\n        white-space:nowrap;\n        word-break:keep-all;\n\n        word-wrap:normal;\n        overflow-wrap: normal;\n\n        text-overflow:@style;\n        overflow:hidden;\n    }\n\n    // 折行\n    .break(@lines: auto, @inline: false) {\n        // 单行折行处理\n        & when (@lines = auto) {\n            white-space: normal;\n            word-break: break-all;\n            word-wrap: break-word;\n            overflow-wrap: break-word;\n            hyphens: auto;\n            line-break: strict;\n        }\n        // 多行折行处理\n        & when not (@lines = auto) {\n            display: if(@inline, -webkit-inline-box, -webkit-box);\n            -webkit-line-clamp: @lines;\n            -webkit-box-orient: vertical;\n            overflow: hidden;\n        }\n    }\n\n    // Special Write Mode\n    // 书写模式：牌匾从右至左水平单行排版效果\n    .retex